import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  // Don't show navbar on admin pages
  if (location.pathname.startsWith('/admin')) {
    return null;
  }

  return (
    <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
      <div className="container">
        <Link className="navbar-brand fw-bold" to="/">
          🎬 FlixGo
        </Link>
        
        <button 
          className="navbar-toggler" 
          type="button" 
          data-bs-toggle="collapse" 
          data-bs-target="#navbarNav"
        >
          <span className="navbar-toggler-icon"></span>
        </button>
        
        <div className="collapse navbar-collapse" id="navbarNav">
          <ul className="navbar-nav me-auto">
            <li className="nav-item">
              <a 
                className="nav-link" 
                href="/"
                onClick={(e) => {
                  // If we're not on home page, navigate to home page
                  if (location.pathname !== '/') {
                    window.location.href = '/';
                    return;
                  }
                  
                  // If we're on home page, smooth scroll to top
                  e.preventDefault();
                  window.scrollTo({ 
                    top: 0, 
                    behavior: 'smooth' 
                  });
                }}
              >
                Home
              </a>
            </li>
            <li className="nav-item">
              <a 
                className="nav-link" 
                href="#movies"
                onClick={(e) => {
                  // If we're not on home page, navigate to home first
                  if (location.pathname !== '/') {
                    window.location.href = '/#movies';
                    return;
                  }
                  
                  // If we're on home page, smooth scroll to movies section
                  e.preventDefault();
                  const moviesSection = document.getElementById('movies');
                  if (moviesSection) {
                    moviesSection.scrollIntoView({ 
                      behavior: 'smooth',
                      block: 'start'
                    });
                  }
                }}
              >
                Movies
              </a>
            </li>
          </ul>
          
          <ul className="navbar-nav">
            {user ? (
              <>
                {user.role === 'admin' && (
                  <li className="nav-item">
                    <Link 
                      className="nav-link bg-warning text-dark fw-bold px-3 rounded me-2 admin-panel-btn" 
                      to="/admin/dashboard"
                      style={{ fontSize: '0.9em' }}
                    >
                      🔐 Admin Panel
                    </Link>
                  </li>
                )}
                <li className="nav-item">
                  <Link className="nav-link" to="/profile">
                    👤 {user.name}
                    {user.role === 'admin' && (
                      <span className="badge bg-danger ms-1" style={{ fontSize: '0.7em' }}>Admin</span>
                    )}
                  </Link>
                </li>
                <li className="nav-item">
                  <button 
                    className="nav-link btn btn-link text-decoration-none"
                    onClick={handleLogout}
                  >
                    Logout
                  </button>
                </li>
              </>
            ) : (
              <>
                <li className="nav-item">
                  <Link className="nav-link" to="/login">Login</Link>
                </li>
                <li className="nav-item">
                  <Link className="nav-link" to="/register">Register</Link>
                </li>
              </>
            )}
          </ul>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
