import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Footer = () => {
  const location = useLocation();

  // Only show footer on home page
  if (location.pathname !== '/') {
    return null;
  }

  return (
    <footer className="bg-dark text-white mt-auto py-4">
      <div className="container">
        <div className="row">
          {/* Company Info */}
          <div className="col-md-4 mb-3">
            <h5 className="fw-bold mb-3">🎬 FlixGo</h5>
            <p className="text-light mb-2">
              Your ultimate destination for movie ticket booking. Experience cinema like never before with seamless booking and premium service.
            </p>
          </div>

          {/* Quick Links */}
          <div className="col-md-2 mb-3">
            <h6 className="fw-bold mb-3">Quick Links</h6>
            <ul className="list-unstyled">
              <li className="mb-2">
                <Link 
                  to="/" 
                  className="text-light text-decoration-none footer-link"
                >
                  🏠 Home
                </Link>
              </li>
              <li className="mb-2">
                <a 
                  href="#movies"
                  className="text-light text-decoration-none footer-movies-link"
                  onClick={(e) => {
                    // If we're not on home page, navigate to home first
                    if (location.pathname !== '/') {
                      window.location.href = '/#movies';
                      return;
                    }
                    
                    // If we're on home page, smooth scroll to movies section
                    e.preventDefault();
                    const moviesSection = document.getElementById('movies');
                    if (moviesSection) {
                      moviesSection.scrollIntoView({ 
                        behavior: 'smooth',
                        block: 'start'
                      });
                    }
                  }}
                >
                  🎬 Movies
                </a>
              </li>
              <li className="mb-2">
                <Link 
                  to="/profile" 
                  className="text-light text-decoration-none footer-link"
                >
                  👤 My Profile
                </Link>
              </li>
            </ul>
          </div>

          {/* Services */}
          <div className="col-md-2 mb-3">
            <h6 className="fw-bold mb-3">Services</h6>
            <ul className="list-unstyled">
              <li className="mb-2">
                <span className="text-light">🎟️ Online Booking</span>
              </li>
              <li className="mb-2">
                <span className="text-light">💺 Seat Selection</span>
              </li>
              <li className="mb-2">
                <span className="text-light">🍿 Snack Combo</span>
              </li>
              <li className="mb-2">
                <span className="text-light">📱 Mobile Tickets</span>
              </li>
            </ul>
          </div>

          {/* Contact Info */}
          <div className="col-md-4 mb-3">
            <h6 className="fw-bold mb-3">Contact Information</h6>
            <div className="mb-2">
              <span className="text-light">
                <strong>📍 Address:</strong><br/>
                91 Cinema Street, Movie District<br/>
                Entertainment City, 395004
              </span>
            </div>
            <div className="mb-2">
              <span className="text-light">
                <strong>📞 Phone:</strong> +(91) 8128677032
              </span>
            </div>
            <div className="mb-2">
              <span className="text-light">
                <strong>📧 Email:</strong> info@filxgo.com
              </span>
            </div>
            <div className="mb-2">
              <span className="text-light">
                <strong>🕒 Support Hours:</strong> 24/7
              </span>
            </div>
          </div>
        </div>

        <hr className="my-4 bg-light" />

        {/* Bottom Copyright */}
        <div className="row">
          <div className="col-md-6">
            <p className="mb-0 text-light">
              &copy; 2025 FlixGo. All rights reserved.
            </p>
          </div>
          <div className="col-md-6 text-md-end">
            <span className="text-light">
              Made with ❤️ for movie lovers
            </span>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
