import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import axios from 'axios';

const AdminTheaters = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  
  const [theaters, setTheaters] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingTheater, setEditingTheater] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    location: {
      address: '',
      city: '',
      state: '',
      pincode: ''
    },
    screens: [
      {
        screenNumber: 'Screen 1',
        screenType: 'Regular',
        totalSeats: 100
      }
    ],
    amenities: [],
    contact: {
      phone: '',
      email: ''
    },
    operatingHours: {
      openTime: '09:00',
      closeTime: '23:00'
    },
    image: '',
    rating: 4.0,
    status: 'active'
  });

  const screenTypes = ['Regular', 'IMAX', '4DX', 'Dolby Atmos', 'Premium'];
  const amenityOptions = ['Parking', 'Food Court', 'Restaurant', 'ATM', 'Wheelchair Access', 'Air Conditioning', 'Security'];
  const statusOptions = ['active', 'inactive', 'maintenance'];

  useEffect(() => {
    fetchTheaters();
  }, []);

  const fetchTheaters = async () => {
    try {
      const token = localStorage.getItem('token');
      if (token) {
        axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
      }
      
      const response = await axios.get('http://localhost:5000/api/theaters');
      setTheaters(response.data.data);
    } catch (error) {
      console.error('Error fetching theaters:', error);
      if (error.response?.status === 401 || error.response?.status === 403) {
        logout();
        navigate('/');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    try {
      const theaterData = {
        ...formData,
        rating: parseFloat(formData.rating),
        screens: formData.screens.map(screen => ({
          ...screen,
          totalSeats: parseInt(screen.totalSeats)
        }))
      };

      if (editingTheater) {
        await axios.put(`http://localhost:5000/api/theaters/${editingTheater._id}`, theaterData);
      } else {
        await axios.post('http://localhost:5000/api/theaters', theaterData);
      }

      setShowModal(false);
      setEditingTheater(null);
      resetForm();
      fetchTheaters();
    } catch (error) {
      console.error('Error saving theater:', error);
      alert('Error saving theater. Please try again.');
    }
  };

  const handleEdit = (theater) => {
    setEditingTheater(theater);
    setFormData({
      name: theater.name,
      location: theater.location,
      screens: theater.screens.length > 0 ? theater.screens : [
        { screenNumber: 'Screen 1', screenType: 'Regular', totalSeats: 100 }
      ],
      amenities: theater.amenities || [],
      contact: theater.contact || { phone: '', email: '' },
      operatingHours: theater.operatingHours || { openTime: '09:00', closeTime: '23:00' },
      image: theater.image || '',
      rating: theater.rating || 4.0,
      status: theater.status || 'active'
    });
    setShowModal(true);
  };

  const handleDelete = async (theaterId) => {
    if (window.confirm('Are you sure you want to delete this theater? This action cannot be undone.')) {
      try {
        await axios.delete(`http://localhost:5000/api/theaters/${theaterId}`);
        fetchTheaters();
      } catch (error) {
        console.error('Error deleting theater:', error);
        alert(error.response?.data?.message || 'Error deleting theater. Please try again.');
      }
    }
  };

  const resetForm = () => {
    setFormData({
      name: '',
      location: { address: '', city: '', state: '', pincode: '' },
      screens: [{ screenNumber: 'Screen 1', screenType: 'Regular', totalSeats: 100 }],
      amenities: [],
      contact: { phone: '', email: '' },
      operatingHours: { openTime: '09:00', closeTime: '23:00' },
      image: '',
      rating: 4.0,
      status: 'active'
    });
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: value
        }
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleScreenChange = (index, field, value) => {
    const updatedScreens = [...formData.screens];
    updatedScreens[index] = {
      ...updatedScreens[index],
      [field]: field === 'totalSeats' ? parseInt(value) || 100 : value
    };
    setFormData(prev => ({
      ...prev,
      screens: updatedScreens
    }));
  };

  const addScreen = () => {
    setFormData(prev => ({
      ...prev,
      screens: [
        ...prev.screens,
        {
          screenNumber: `Screen ${prev.screens.length + 1}`,
          screenType: 'Regular',
          totalSeats: 100
        }
      ]
    }));
  };

  const removeScreen = (index) => {
    if (formData.screens.length > 1) {
      setFormData(prev => ({
        ...prev,
        screens: prev.screens.filter((_, i) => i !== index)
      }));
    }
  };

  const handleAmenityChange = (amenity) => {
    setFormData(prev => ({
      ...prev,
      amenities: prev.amenities.includes(amenity)
        ? prev.amenities.filter(a => a !== amenity)
        : [...prev.amenities, amenity]
    }));
  };

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <div className="min-vh-100" style={{ background: '#f8f9fa' }}>
      {/* Admin Header */}
      <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
        <div className="container-fluid">
          <Link className="navbar-brand fw-bold" to="/admin/dashboard">
            🎬 CineBook Admin
          </Link>
          
          <div className="navbar-nav ms-auto">
            <div className="nav-item dropdown">
              <button 
                className="btn btn-outline-light dropdown-toggle"
                type="button"
                id="dropdownMenuButton"
                data-bs-toggle="dropdown"
                aria-expanded="false"
              >
                👤 {user?.name}
              </button>
              <ul className="dropdown-menu" aria-labelledby="dropdownMenuButton">
                <li><button className="dropdown-item" onClick={handleLogout}>Logout</button></li>
              </ul>
            </div>
          </div>
        </div>
      </nav>

      <div className="container-fluid">
        <div className="row">
          {/* Sidebar */}
          <div className="col-md-2 admin-sidebar">
            <div className="nav flex-column nav-pills">
              <Link className="nav-link" to="/admin/dashboard">
                📊 Dashboard
              </Link>
              <Link className="nav-link" to="/admin/movies">
                🎬 Manage Movies
              </Link>
              <Link className="nav-link" to="/admin/shows">
                🎪 Manage Shows
              </Link>
              <Link className="nav-link active" to="/admin/theaters">
                🏢 Manage Theaters
              </Link>
            </div>
          </div>

          {/* Main Content */}
          <div className="col-md-10 p-4">
            <div className="d-flex justify-content-between align-items-center mb-4">
              <h1 className="h3">Manage Theaters</h1>
              <button
                className="btn btn-primary"
                onClick={() => {
                  resetForm();
                  setEditingTheater(null);
                  setShowModal(true);
                }}
              >
                ➕ Add New Theater
              </button>
            </div>

            {loading ? (
              <div className="text-center py-5">
                <div className="spinner-border text-primary" role="status">
                  <span className="visually-hidden">Loading...</span>
                </div>
              </div>
            ) : (
              <div className="card">
                <div className="card-body">
                  <div className="table-responsive">
                    <table className="table table-striped">
                      <thead>
                        <tr>
                          <th>Name</th>
                          <th>Location</th>
                          <th>Screens</th>
                          <th>Contact</th>
                          <th>Rating</th>
                          <th>Status</th>
                          <th>Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {theaters.map(theater => (
                          <tr key={theater._id}>
                            <td>
                              <div>
                                <strong>{theater.name}</strong>
                                {theater.image && (
                                  <br />
                                )}
                                <small className="text-muted">
                                  {theater.amenities?.slice(0, 2).join(', ')}
                                  {theater.amenities?.length > 2 && ' +more'}
                                </small>
                              </div>
                            </td>
                            <td>
                              <div>
                                <div>{theater.location.city}, {theater.location.state}</div>
                                <small className="text-muted">{theater.location.address}</small>
                              </div>
                            </td>
                            <td>
                              <div>
                                <span className="badge bg-info">{theater.screens.length} screens</span>
                                <br />
                                <small className="text-muted">
                                  {theater.screens.reduce((acc, screen) => acc + screen.totalSeats, 0)} total seats
                                </small>
                              </div>
                            </td>
                            <td>
                              <div>
                                {theater.contact?.phone && (
                                  <>📞 {theater.contact.phone}<br /></>
                                )}
                                {theater.contact?.email && (
                                  <small className="text-muted">📧 {theater.contact.email}</small>
                                )}
                              </div>
                            </td>
                            <td>
                              <span className="badge bg-warning text-dark">
                                ⭐ {theater.rating}
                              </span>
                            </td>
                            <td>
                              <span className={`badge ${
                                theater.status === 'active' ? 'bg-success' : 
                                theater.status === 'inactive' ? 'bg-secondary' : 'bg-warning text-dark'
                              }`}>
                                {theater.status}
                              </span>
                            </td>
                            <td>
                              <div className="btn-group" role="group">
                                <button
                                  className="btn btn-sm btn-outline-primary"
                                  onClick={() => handleEdit(theater)}
                                >
                                  Edit
                                </button>
                                <button
                                  className="btn btn-sm btn-outline-danger"
                                  onClick={() => handleDelete(theater._id)}
                                >
                                  Delete
                                </button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>

                    {theaters.length === 0 && (
                      <div className="text-center py-4">
                        <p className="text-muted">No theaters found. Add your first theater!</p>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Theater Modal */}
      {showModal && (
        <div className="modal show d-block" style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <div className="modal-dialog modal-xl">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title">
                  {editingTheater ? 'Edit Theater' : 'Add New Theater'}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <form onSubmit={handleSubmit}>
                <div className="modal-body">
                  {/* Basic Info */}
                  <div className="row">
                    <div className="col-md-6">
                      <div className="mb-3">
                        <label className="form-label">Theater Name *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="name"
                          value={formData.name}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                    <div className="col-md-3">
                      <div className="mb-3">
                        <label className="form-label">Status *</label>
                        <select
                          className="form-select"
                          name="status"
                          value={formData.status}
                          onChange={handleInputChange}
                          required
                        >
                          {statusOptions.map(status => (
                            <option key={status} value={status}>
                              {status.charAt(0).toUpperCase() + status.slice(1)}
                            </option>
                          ))}
                        </select>
                      </div>
                    </div>
                    <div className="col-md-3">
                      <div className="mb-3">
                        <label className="form-label">Rating (1-5) *</label>
                        <input
                          type="number"
                          step="0.1"
                          min="1"
                          max="5"
                          className="form-control"
                          name="rating"
                          value={formData.rating}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                  </div>

                  {/* Location */}
                  <h6 className="mt-4 mb-3">📍 Location Details</h6>
                  <div className="row">
                    <div className="col-md-12">
                      <div className="mb-3">
                        <label className="form-label">Address *</label>
                        <textarea
                          className="form-control"
                          name="location.address"
                          value={formData.location.address}
                          onChange={handleInputChange}
                          rows="2"
                          required
                        ></textarea>
                      </div>
                    </div>
                  </div>
                  
                  <div className="row">
                    <div className="col-md-4">
                      <div className="mb-3">
                        <label className="form-label">City *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="location.city"
                          value={formData.location.city}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                    <div className="col-md-4">
                      <div className="mb-3">
                        <label className="form-label">State *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="location.state"
                          value={formData.location.state}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                    <div className="col-md-4">
                      <div className="mb-3">
                        <label className="form-label">Pincode *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="location.pincode"
                          value={formData.location.pincode}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                  </div>

                  {/* Screens */}
                  <h6 className="mt-4 mb-3">🎬 Screens</h6>
                  {formData.screens.map((screen, index) => (
                    <div key={index} className="card mb-3">
                      <div className="card-body">
                        <div className="d-flex justify-content-between align-items-center mb-2">
                          <h6 className="card-title mb-0">Screen {index + 1}</h6>
                          {formData.screens.length > 1 && (
                            <button
                              type="button"
                              className="btn btn-sm btn-outline-danger"
                              onClick={() => removeScreen(index)}
                            >
                              Remove
                            </button>
                          )}
                        </div>
                        <div className="row">
                          <div className="col-md-4">
                            <div className="mb-3">
                              <label className="form-label">Screen Number</label>
                              <input
                                type="text"
                                className="form-control"
                                value={screen.screenNumber}
                                onChange={(e) => handleScreenChange(index, 'screenNumber', e.target.value)}
                              />
                            </div>
                          </div>
                          <div className="col-md-4">
                            <div className="mb-3">
                              <label className="form-label">Screen Type</label>
                              <select
                                className="form-select"
                                value={screen.screenType}
                                onChange={(e) => handleScreenChange(index, 'screenType', e.target.value)}
                              >
                                {screenTypes.map(type => (
                                  <option key={type} value={type}>{type}</option>
                                ))}
                              </select>
                            </div>
                          </div>
                          <div className="col-md-4">
                            <div className="mb-3">
                              <label className="form-label">Total Seats</label>
                              <input
                                type="number"
                                className="form-control"
                                value={screen.totalSeats}
                                onChange={(e) => handleScreenChange(index, 'totalSeats', e.target.value)}
                                min="1"
                                max="500"
                              />
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                  
                  <button
                    type="button"
                    className="btn btn-outline-primary mb-3"
                    onClick={addScreen}
                  >
                    + Add Screen
                  </button>

                  {/* Amenities */}
                  <h6 className="mt-4 mb-3">🛎️ Amenities</h6>
                  <div className="row">
                    {amenityOptions.map(amenity => (
                      <div key={amenity} className="col-md-3 mb-2">
                        <div className="form-check">
                          <input
                            className="form-check-input"
                            type="checkbox"
                            id={`amenity-${amenity}`}
                            checked={formData.amenities.includes(amenity)}
                            onChange={() => handleAmenityChange(amenity)}
                          />
                          <label className="form-check-label" htmlFor={`amenity-${amenity}`}>
                            {amenity}
                          </label>
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* Contact & Hours */}
                  <div className="row mt-4">
                    <div className="col-md-6">
                      <h6 className="mb-3">📞 Contact Details</h6>
                      <div className="mb-3">
                        <label className="form-label">Phone</label>
                        <input
                          type="tel"
                          className="form-control"
                          name="contact.phone"
                          value={formData.contact.phone}
                          onChange={handleInputChange}
                        />
                      </div>
                      <div className="mb-3">
                        <label className="form-label">Email</label>
                        <input
                          type="email"
                          className="form-control"
                          name="contact.email"
                          value={formData.contact.email}
                          onChange={handleInputChange}
                        />
                      </div>
                    </div>
                    
                    <div className="col-md-6">
                      <h6 className="mb-3">🕒 Operating Hours</h6>
                      <div className="mb-3">
                        <label className="form-label">Opening Time</label>
                        <input
                          type="time"
                          className="form-control"
                          name="operatingHours.openTime"
                          value={formData.operatingHours.openTime}
                          onChange={handleInputChange}
                        />
                      </div>
                      <div className="mb-3">
                        <label className="form-label">Closing Time</label>
                        <input
                          type="time"
                          className="form-control"
                          name="operatingHours.closeTime"
                          value={formData.operatingHours.closeTime}
                          onChange={handleInputChange}
                        />
                      </div>
                    </div>
                  </div>

                  {/* Image URL */}
                  <div className="mb-3">
                    <label className="form-label">Theater Image URL</label>
                    <input
                      type="url"
                      className="form-control"
                      name="image"
                      value={formData.image}
                      onChange={handleInputChange}
                      placeholder="https://example.com/theater-image.jpg"
                    />
                  </div>
                </div>
                
                <div className="modal-footer">
                  <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={() => setShowModal(false)}
                  >
                    Cancel
                  </button>
                  <button type="submit" className="btn btn-primary">
                    {editingTheater ? 'Update Theater' : 'Add Theater'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminTheaters;
