import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate, Link } from 'react-router-dom';
import axios from 'axios';

const Confirmation = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [paymentProcessing, setPaymentProcessing] = useState(false);
  const [paymentCompleted, setPaymentCompleted] = useState(false);

  // Get booking details from navigation state
  const booking = location.state?.booking;
  const totalAmount = location.state?.totalAmount;

  useEffect(() => {
    if (!booking) {
      navigate('/');
    }
  }, [booking, navigate]);

  const handlePayment = async () => {
    setPaymentProcessing(true);

    // Simulate payment processing
    setTimeout(async () => {
      try {
        // Update payment status in backend
        const token = localStorage.getItem('token');
        await axios.put(`http://localhost:5000/api/bookings/${booking._id}/payment`, {
          paymentStatus: 'completed'
        }, {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        });

        setPaymentCompleted(true);
        setPaymentProcessing(false);
      } catch (error) {
        console.error('Payment update error:', error);
        alert('Payment processing failed. Please contact support.');
        setPaymentProcessing(false);
      }
    }, 2000); // Simulate 2-second payment processing
  };

  const formatDate = (dateString) => {
    const options = { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric'
    };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  if (!booking) {
    return null;
  }

  if (paymentCompleted) {
    return (
      <div className="container mt-5">
        <div className="row justify-content-center">
          <div className="col-md-8">
            <div className="card border-success">
              <div className="card-body text-center p-5">
                <div className="mb-4">
                  <div className="text-success display-1">✓</div>
                  <h2 className="text-success mb-3">Booking Confirmed!</h2>
                  <p className="text-muted">Please pay at the theater counter before the show</p>
                </div>

                <div className="card mb-4">
                  <div className="card-header bg-success text-white">
                    <h5 className="mb-0">Booking Confirmation</h5>
                  </div>
                  <div className="card-body">
                    <div className="row text-start">
                      <div className="col-md-6">
                        <p><strong>Booking ID:</strong> {booking.bookingId}</p>
                        <p><strong>Movie:</strong> {booking.movieId.title}</p>
                        {booking.showId.theaterId && (
                          <p><strong>Theater:</strong> {booking.showId.theaterId.name}</p>
                        )}
                        <p><strong>Date:</strong> {formatDate(booking.showId.date)}</p>
                        <p><strong>Time:</strong> {booking.showId.time}</p>
                      </div>
                      <div className="col-md-6">
                        {booking.showId.theaterId?.location && (
                          <p><strong>Location:</strong> {booking.showId.theaterId.location.city}</p>
                        )}
                        <p><strong>Screen:</strong> {booking.showId.screen}</p>
                        <p><strong>Seats:</strong> {booking.seats.join(', ')}</p>
                        <p><strong>Total Amount:</strong> ₹{booking.totalAmount}</p>
                        <p><strong>Status:</strong> <span className="badge bg-success">Confirmed</span></p>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="alert alert-info">
                  <h6>Important Instructions:</h6>
                  <ul className="text-start mb-0">
                    <li><strong>Payment:</strong> Pay ₹{booking.totalAmount} at the theater counter</li>
                    <li>Please arrive at the cinema 15 minutes before the show time</li>
                    <li>Carry a valid ID proof for verification</li>
                    <li>Present your booking ID at the counter</li>
                    <li>No outside food or beverages allowed</li>
                  </ul>
                </div>

                <div className="d-flex gap-3 justify-content-center">
                  <Link to="/profile" className="btn btn-outline-primary">
                    View My Bookings
                  </Link>
                  <Link to="/" className="btn btn-primary">
                    Book Another Movie
                  </Link>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-8">
          <div className="card">
            <div className="card-header">
              <h3 className="mb-0">Booking Summary</h3>
            </div>
            <div className="card-body">
              {/* Movie and Show Details */}
              <div className="row mb-4">
                <div className="col-md-6">
                  <h5>Movie Details</h5>
                  <p className="mb-1"><strong>Title:</strong> {booking.movieId.title}</p>
                  <p className="mb-1"><strong>Genre:</strong> {booking.movieId.genre}</p>
                  <p className="mb-1"><strong>Language:</strong> {booking.movieId.language}</p>
                  <p className="mb-0"><strong>Duration:</strong> {booking.movieId.duration} mins</p>
                </div>
                <div className="col-md-6">
                  <h5>Show Details</h5>
                  <p className="mb-1"><strong>Date:</strong> {formatDate(booking.showId.date)}</p>
                  <p className="mb-1"><strong>Time:</strong> {booking.showId.time}</p>
                  <p className="mb-1"><strong>Screen:</strong> {booking.showId.screen}</p>
                  <p className="mb-0"><strong>Seats:</strong> {booking.seats.join(', ')}</p>
                </div>
              </div>

              {/* Booking Details */}
              <div className="card bg-light mb-4">
                <div className="card-body">
                  <div className="row">
                    <div className="col-md-8">
                      <h6 className="mb-1">Booking ID: {booking.bookingId}</h6>
                      <p className="text-muted mb-0">
                        Number of Seats: {booking.seats.length}
                      </p>
                    </div>
                    <div className="col-md-4 text-md-end">
                      <h4 className="text-primary mb-0">₹{booking.totalAmount}</h4>
                      <small className="text-muted">Total Amount</small>
                    </div>
                  </div>
                </div>
              </div>

              {/* Payment Section */}
              <div className="card border-primary">
                <div className="card-header bg-primary text-white">
                  <h5 className="mb-0">💰 Payment</h5>
                </div>
                <div className="card-body">
                  <div className="mb-3">
                    <h6>Payment Method</h6>
                    <div className="form-check">
                      <input 
                        className="form-check-input" 
                        type="radio" 
                        name="paymentMethod" 
                        id="cashOnTheater" 
                        checked 
                        readOnly
                      />
                      <label className="form-check-label" htmlFor="cashOnTheater">
                        <strong>💵 Cash on Theater</strong>
                        <br />
                        <small className="text-muted">Pay directly at the theater counter before the show</small>
                      </label>
                    </div>
                  </div>
                  
                  <div className="alert alert-info">
                    <strong>Note:</strong> Please carry the exact amount and arrive 15 minutes early to complete payment at the theater counter.
                  </div>

                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <h6>Amount to Pay: ₹{booking.totalAmount}</h6>
                      <small className="text-muted">Secure payment powered by FlixGo</small>
                    </div>
                    <button
                      className="btn btn-success btn-lg"
                      onClick={handlePayment}
                      disabled={paymentProcessing}
                    >
                      {paymentProcessing ? (
                        <>
                          <span className="spinner-border spinner-border-sm me-2" role="status"></span>
                          Confirming Booking...
                        </>
                      ) : (
                        '✅ Confirm Booking'
                      )}
                    </button>
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="d-flex justify-content-between mt-4">
                <button
                  className="btn btn-outline-secondary"
                  onClick={() => navigate(-1)}
                  disabled={paymentProcessing}
                >
                  ← Back to Seat Selection
                </button>
                <small className="text-muted align-self-center">
                  Confirm your booking (Payment required at theater)
                </small>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Confirmation;
