import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import axios from 'axios';

const SeatSelection = () => {
  const { showId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  
  const [show, setShow] = useState(null);
  const [selectedSeats, setSelectedSeats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [bookingLoading, setBookingLoading] = useState(false);

  useEffect(() => {
    fetchShowDetails();
  }, [showId]);

  const fetchShowDetails = async () => {
    try {
      const response = await axios.get(`http://localhost:5000/api/shows/${showId}`);
      setShow(response.data.data);
    } catch (error) {
      setError('Show not found');
      console.error('Error fetching show:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSeatClick = (seatNumber) => {
    const seat = show.availableSeats.find(s => s.seatNumber === seatNumber);
    
    if (seat.isBooked) return;

    if (selectedSeats.includes(seatNumber)) {
      setSelectedSeats(selectedSeats.filter(s => s !== seatNumber));
    } else {
      if (selectedSeats.length < 10) { // Max 10 seats per booking
        setSelectedSeats([...selectedSeats, seatNumber]);
      }
    }
  };

  const getSeatClass = (seatNumber) => {
    const seat = show.availableSeats.find(s => s.seatNumber === seatNumber);
    
    if (seat.isBooked) return 'seat booked';
    if (selectedSeats.includes(seatNumber)) return 'seat selected';
    return 'seat available';
  };

  const handleBooking = async () => {
    if (!user) {
      alert('Please login to book tickets');
      navigate('/login');
      return;
    }

    if (selectedSeats.length === 0) {
      alert('Please select at least one seat');
      return;
    }

    setBookingLoading(true);
    
    try {
      console.log('Starting booking process...', { 
        movieId: show.movieId._id, 
        showId: show._id, 
        seats: selectedSeats 
      });

      // Get auth token
      const token = localStorage.getItem('token');
      if (!token) {
        alert('Please login to continue');
        navigate('/login');
        return;
      }

      // Create the booking (this will also book the seats atomically)
      const bookingResponse = await axios.post('http://localhost:5000/api/bookings', {
        movieId: show.movieId._id,
        showId: show._id,
        seats: selectedSeats
      }, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      console.log('Booking response:', bookingResponse.data);

      // Navigate to confirmation page with booking details
      navigate('/confirmation', { 
        state: { 
          booking: bookingResponse.data.data,
          totalAmount: selectedSeats.length * show.price
        } 
      });
    } catch (error) {
      console.error('Booking error:', error);
      
      if (error.response?.status === 401) {
        alert('Please login to continue');
        navigate('/login');
      } else if (error.response?.status === 400) {
        // Seat availability error - refresh show data
        alert(error.response?.data?.message || 'Some seats are no longer available');
        fetchShowDetails(); // Refresh the seat data
      } else {
        alert(error.response?.data?.message || 'Booking failed. Please try again.');
      }
    } finally {
      setBookingLoading(false);
    }
  };

  const formatDate = (dateString) => {
    const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  const renderSeatLayout = () => {
    if (!show || !show.availableSeats) return null;

    const rows = 10; // 10 rows
    const seatsPerRow = 10; // 10 seats per row
    const seatLayout = [];

    for (let row = 0; row < rows; row++) {
      const rowSeats = [];
      const rowLabel = String.fromCharCode(65 + row); // A, B, C, etc.
      
      for (let seat = 1; seat <= seatsPerRow; seat++) {
        const seatNumber = `${rowLabel}${seat}`;
        const seatExists = show.availableSeats.find(s => s.seatNumber === seatNumber);
        
        // Add gap in the middle (after seat 5)
        if (seat === 6) {
          rowSeats.push(<div key={`gap-${row}-${seat}`} className="seat-gap"></div>);
        }
        
        if (seatExists) {
          rowSeats.push(
            <div
              key={seatNumber}
              className={getSeatClass(seatNumber)}
              onClick={() => handleSeatClick(seatNumber)}
              title={seatNumber}
            >
              {seat}
            </div>
          );
        } else {
          // For seats that don't exist in the database, render as unavailable
          rowSeats.push(
            <div 
              key={seatNumber} 
              className="seat unavailable"
              title={seatNumber}
            >
              {seat}
            </div>
          );
        }
      }

      seatLayout.push(
        <div key={row} className="seat-row">
          <div className="row-label me-3 text-white">{rowLabel}</div>
          <div className="seats-container">
            {rowSeats}
          </div>
          <div className="row-label ms-3 text-white">{rowLabel}</div>
        </div>
      );
    }

    return seatLayout;
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ height: '50vh' }}>
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
      </div>
    );
  }

  if (error || !show) {
    return (
      <div className="container mt-5">
        <div className="text-center">
          <h2 className="text-danger">{error || 'Show not found'}</h2>
          <button onClick={() => navigate(-1)} className="btn btn-primary mt-3">Go Back</button>
        </div>
      </div>
    );
  }

  return (
    <div className="container mt-4">
      {/* Show Information */}
      <div className="card mb-4">
        <div className="card-body">
          <div className="row align-items-center">
            <div className="col-md-8">
              <h4 className="mb-2">{show.movieId.title}</h4>
              
              {/* Theater Information */}
              <div className="mb-2">
                <h6 className="text-primary mb-1">
                  <i className="fas fa-building me-2"></i>
                  {show.theaterId.name}
                </h6>
                <p className="mb-1 text-muted small">
                  <i className="fas fa-map-marker-alt me-2"></i>
                  {show.theaterId.location.address}, {show.theaterId.location.city}
                </p>
              </div>
              
              <p className="mb-1 text-muted">
                <strong>Date:</strong> {formatDate(show.date)} | 
                <strong> Time:</strong> {show.time} | 
                <strong> Screen:</strong> {show.screen}
              </p>
              <p className="mb-0 text-muted">
                <strong>Price per seat:</strong> ₹{show.price}
              </p>
            </div>
            <div className="col-md-4 text-md-end">
              <h5 className="text-primary mb-0">
                Selected: {selectedSeats.length} seat(s)
              </h5>
              <p className="mb-0">
                <strong>Total: ₹{selectedSeats.length * show.price}</strong>
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Screen */}
      <div className="screen text-center mb-4">
        SCREEN
      </div>

      {/* Seat Layout */}
      <div className="seat-layout mb-4">
        {renderSeatLayout()}
      </div>

      {/* Legend */}
      <div className="seat-legend">
        <div className="legend-item">
          <div className="seat available"></div>
          <span className="text-white">Available</span>
        </div>
        <div className="legend-item">
          <div className="seat selected"></div>
          <span className="text-white">Selected</span>
        </div>
        <div className="legend-item">
          <div className="seat booked"></div>
          <span className="text-white">Booked</span>
        </div>
        <div className="legend-item">
          <div className="seat unavailable"></div>
          <span className="text-white">Unavailable</span>
        </div>
      </div>

      {/* Selected Seats Info */}
      {selectedSeats.length > 0 && (
        <div className="card mb-4">
          <div className="card-body">
            <h6>Selected Seats:</h6>
            <p className="mb-0">
              {selectedSeats.join(', ')}
            </p>
          </div>
        </div>
      )}

      {/* Action Buttons */}
      <div className="d-flex justify-content-between">
        <button
          className="btn btn-outline-light"
          onClick={() => navigate(-1)}
        >
          ← Back
        </button>
        
        <button
          className="btn btn-primary"
          onClick={handleBooking}
          disabled={selectedSeats.length === 0 || bookingLoading}
        >
          {bookingLoading ? (
            <>
              <span className="spinner-border spinner-border-sm me-2" role="status"></span>
              Processing...
            </>
          ) : (
            `Proceed to Pay (₹${selectedSeats.length * show.price})`
          )}
        </button>
      </div>
    </div>
  );
};

export default SeatSelection;
