import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import axios from 'axios';

const Profile = () => {
  const { user, updateProfile } = useAuth();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('bookings');
  const [profileData, setProfileData] = useState({
    name: user?.name || '',
    email: user?.email || ''
  });
  const [profileLoading, setProfileLoading] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    fetchBookings();
    setProfileData({
      name: user?.name || '',
      email: user?.email || ''
    });
  }, [user]);

  const fetchBookings = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/bookings/my-bookings', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      setBookings(response.data.data || []);
      console.log('Fetched bookings:', response.data.data);
    } catch (error) {
      console.error('Error fetching bookings:', error);
      if (error.response?.status === 401) {
        // Token expired or invalid
        localStorage.removeItem('token');
        window.location.href = '/login';
      }
    } finally {
      setLoading(false);
    }
  };

  const handleProfileUpdate = async (e) => {
    e.preventDefault();
    setProfileLoading(true);
    setMessage('');

    const result = await updateProfile(profileData.name, profileData.email);
    
    if (result.success) {
      setMessage('Profile updated successfully!');
    } else {
      setMessage(result.message || 'Update failed');
    }
    
    setProfileLoading(false);
    
    // Clear message after 3 seconds
    setTimeout(() => setMessage(''), 3000);
  };

  const handleInputChange = (e) => {
    setProfileData({
      ...profileData,
      [e.target.name]: e.target.value
    });
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'Date not available';
    
    try {
      const options = { 
        weekday: 'short', 
        year: 'numeric', 
        month: 'short', 
        day: 'numeric'
      };
      const date = new Date(dateString);
      if (isNaN(date.getTime())) {
        return 'Invalid date';
      }
      return date.toLocaleDateString(undefined, options);
    } catch (error) {
      console.error('Date formatting error:', error);
      return 'Date not available';
    }
  };

  const getStatusBadge = (status) => {
    const statusClasses = {
      'completed': 'bg-success',
      'pending': 'bg-warning text-dark',
      'failed': 'bg-danger',
      'refunded': 'bg-secondary'
    };
    
    return `badge ${statusClasses[status] || 'bg-secondary'}`;
  };

  if (loading && activeTab === 'bookings') {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ height: '50vh' }}>
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mt-4">
      <div className="row">
        {/* Sidebar */}
        <div className="col-md-3">
          <div className="card">
            <div className="card-body text-center">
              <div className="mb-3">
                <div className="bg-primary text-white rounded-circle d-inline-flex align-items-center justify-content-center" 
                     style={{ width: '80px', height: '80px', fontSize: '2rem' }}>
                  {user?.name?.charAt(0)?.toUpperCase()}
                </div>
              </div>
              <h5 className="card-title">{user?.name}</h5>
              <p className="text-muted">{user?.email}</p>
            </div>
          </div>
          
          <div className="list-group mt-3">
            <button
              className={`list-group-item list-group-item-action ${activeTab === 'bookings' ? 'active' : ''}`}
              onClick={() => setActiveTab('bookings')}
            >
              🎟️ My Bookings
            </button>
            <button
              className={`list-group-item list-group-item-action ${activeTab === 'profile' ? 'active' : ''}`}
              onClick={() => setActiveTab('profile')}
            >
              👤 Edit Profile
            </button>
          </div>
        </div>

        {/* Main Content */}
        <div className="col-md-9">
          {activeTab === 'bookings' && (
            <div>
              <div className="d-flex justify-content-between align-items-center mb-4">
                <h3 className="text-white">My Bookings</h3>
                <span className="badge bg-primary fs-6">
                  {bookings.length} booking(s)
                </span>
              </div>

              {bookings.length === 0 ? (
                <div className="card">
                  <div className="card-body text-center py-5">
                    <h5 className="text-muted">No bookings found</h5>
                    <p className="text-muted">You haven't made any bookings yet</p>
                    <a href="/" className="btn btn-primary">
                      Browse Movies
                    </a>
                  </div>
                </div>
              ) : (
                <div className="row">
                  {bookings.map(booking => (
                    <div key={booking._id} className="col-12 mb-4">
                      <div className="card h-100">
                        <div className="card-body">
                          <div className="d-flex justify-content-between align-items-start mb-3">
                            <div>
                              <h6 className="card-title mb-1">
                                {booking.movieId?.title || 'Movie information not available'}
                              </h6>
                              <p className="text-muted small mb-0">
                                Booking ID: {booking.bookingId || 'N/A'}
                              </p>
                            </div>
                            <span className={getStatusBadge(booking.paymentStatus)}>
                              {booking.paymentStatus || 'pending'}
                            </span>
                          </div>

                          {/* Theater Information */}
                          <div className="row mb-3">
                            <div className="col-12">
                              <div className="bg-light p-3 rounded">
                                <div className="row">
                                  <div className="col-md-6">
                                    <h6 className="text-primary mb-2">
                                      <i className="fas fa-building me-2"></i>Theater Information
                                    </h6>
                                    {booking.showId?.theaterId ? (
                                      <>
                                        <p className="mb-1">
                                          <strong>🏢 Theater:</strong> {booking.showId.theaterId.name || 'N/A'}
                                        </p>
                                        {booking.showId.theaterId.location?.city && (
                                          <p className="mb-1">
                                            <strong>📍 Location:</strong> {booking.showId.theaterId.location.city}
                                          </p>
                                        )}
                                        <p className="mb-0">
                                          <strong>🖥️ Screen:</strong> {booking.showId.screen || 'N/A'}
                                        </p>
                                      </>
                                    ) : (
                                      <p className="text-muted mb-0">Theater information not available</p>
                                    )}
                                  </div>
                                  <div className="col-md-6">
                                    <h6 className="text-success mb-2">
                                      <i className="fas fa-calendar-alt me-2"></i>Show Details
                                    </h6>
                                    {booking.showId ? (
                                      <>
                                        <p className="mb-1">
                                          <strong>📅 Date:</strong> {formatDate(booking.showId.date)}
                                        </p>
                                        <p className="mb-0">
                                          <strong>🕐 Time:</strong> {booking.showId.time || 'N/A'}
                                        </p>
                                      </>
                                    ) : (
                                      <p className="text-muted mb-0">Show details not available</p>
                                    )}
                                  </div>
                                </div>
                              </div>
                            </div>
                          </div>

                          {/* Seats and Amount */}
                          <div className="row mb-3">
                            <div className="col-md-6">
                              <div className="bg-warning bg-opacity-10 p-3 rounded">
                                <h6 className="text-warning mb-2">
                                  <i className="fas fa-couch me-2"></i>Seat Information
                                </h6>
                                <p className="mb-0">
                                  <strong>💺 Seats:</strong> 
                                  <span className="badge bg-warning text-dark ms-2">
                                    {booking.seats?.join(', ') || 'N/A'}
                                  </span>
                                </p>
                              </div>
                            </div>
                            <div className="col-md-6">
                              <div className="bg-success bg-opacity-10 p-3 rounded">
                                <h6 className="text-success mb-2">
                                  <i className="fas fa-rupee-sign me-2"></i>Payment Details
                                </h6>
                                <p className="mb-1">
                                  <strong>💰 Total Amount:</strong> 
                                  <span className="badge bg-success ms-2 fs-6">
                                    ₹{booking.totalAmount || 0}
                                  </span>
                                </p>
                                <p className="mb-0 small">
                                  <strong>Payment Mode:</strong> Cash on Theater
                                </p>
                              </div>
                            </div>
                          </div>

                          <div className="d-flex justify-content-between align-items-center mt-2">
                            <div>
                              <span className="badge bg-info">
                                Status: {booking.paymentStatus || 'pending'}
                              </span>
                            </div>
                            <small className="text-muted">
                              <strong>Booked:</strong> {booking.bookingDate ? formatDate(booking.bookingDate) : 'Date not available'}
                            </small>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'profile' && (
            <div>
              <h3 className="text-white mb-4">Edit Profile</h3>
              
              <div className="card">
                <div className="card-body">
                  {message && (
                    <div className={`alert ${message.includes('success') ? 'alert-success' : 'alert-danger'}`}>
                      {message}
                    </div>
                  )}

                  <form onSubmit={handleProfileUpdate}>
                    <div className="mb-3">
                      <label htmlFor="name" className="form-label">Full Name</label>
                      <input
                        type="text"
                        className="form-control"
                        id="name"
                        name="name"
                        value={profileData.name}
                        onChange={handleInputChange}
                        required
                      />
                    </div>

                    <div className="mb-3">
                      <label htmlFor="email" className="form-label">Email Address</label>
                      <input
                        type="email"
                        className="form-control"
                        id="email"
                        name="email"
                        value={profileData.email}
                        onChange={handleInputChange}
                        required
                      />
                    </div>

                    <div className="d-grid">
                      <button
                        type="submit"
                        className="btn btn-primary"
                        disabled={profileLoading}
                      >
                        {profileLoading ? (
                          <>
                            <span className="spinner-border spinner-border-sm me-2" role="status"></span>
                            Updating...
                          </>
                        ) : (
                          'Update Profile'
                        )}
                      </button>
                    </div>
                  </form>

                  <hr className="my-4" />
                  
                  <div className="alert alert-info">
                    <h6>Account Information</h6>
                    <p className="mb-1"><strong>Account Type:</strong> {user?.role === 'admin' ? 'Administrator' : 'Regular User'}</p>
                    <p className="mb-0"><strong>Member Since:</strong> {formatDate(user?.createdAt)}</p>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Profile;
