import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import axios from 'axios';

const AdminMovies = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingMovie, setEditingMovie] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    genre: '',
    description: '',
    duration: '',
    poster: '',
    language: '',
    rating: '',
    trailer: '',
    cast: '',
    releaseDate: ''
  });
  const [selectedFile, setSelectedFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);

  useEffect(() => {
    fetchMovies();
  }, []);

  const fetchMovies = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/movies');
      setMovies(response.data.data);
    } catch (error) {
      console.error('Error fetching movies:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Validate that either a file is selected or URL is provided
    if (!selectedFile && !formData.poster) {
      alert('Please select a poster file or enter a poster URL');
      return;
    }
    
    try {
      // Create FormData for file upload
      const formDataToSend = new FormData();
      
      // Add form fields to FormData
      formDataToSend.append('title', formData.title);
      formDataToSend.append('genre', formData.genre);
      formDataToSend.append('description', formData.description);
      formDataToSend.append('duration', parseInt(formData.duration));
      formDataToSend.append('language', formData.language);
      formDataToSend.append('rating', parseFloat(formData.rating));
      formDataToSend.append('trailer', formData.trailer);
      formDataToSend.append('releaseDate', new Date(formData.releaseDate).toISOString());
      
      // Add cast as string (backend will handle conversion)
      formDataToSend.append('cast', formData.cast);
      
      // Add poster file if selected, otherwise use URL
      if (selectedFile) {
        formDataToSend.append('poster', selectedFile);
      } else if (formData.poster) {
        formDataToSend.append('poster', formData.poster);
      }

      const config = {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      };

      if (editingMovie) {
        await axios.put(`http://localhost:5000/api/movies/${editingMovie._id}`, formDataToSend, config);
      } else {
        await axios.post('http://localhost:5000/api/movies', formDataToSend, config);
      }

      setShowModal(false);
      setEditingMovie(null);
      resetForm();
      fetchMovies();
    } catch (error) {
      console.error('Error saving movie:', error);
      alert('Error saving movie. Please try again.');
    }
  };

  const handleEdit = (movie) => {
    setEditingMovie(movie);
    setFormData({
      title: movie.title,
      genre: movie.genre,
      description: movie.description,
      duration: movie.duration.toString(),
      poster: movie.poster,
      language: movie.language,
      rating: movie.rating.toString(),
      trailer: movie.trailer || '',
      cast: movie.cast.join(', '),
      releaseDate: new Date(movie.releaseDate).toISOString().split('T')[0]
    });
    
    // Clear file selection when editing
    setSelectedFile(null);
    setPreviewUrl(null);
    
    setShowModal(true);
  };

  const handleDelete = async (movieId) => {
    if (window.confirm('Are you sure you want to delete this movie?')) {
      try {
        await axios.delete(`http://localhost:5000/api/movies/${movieId}`);
        fetchMovies();
      } catch (error) {
        console.error('Error deleting movie:', error);
        alert('Error deleting movie. Please try again.');
      }
    }
  };

  const resetForm = () => {
    setFormData({
      title: '',
      genre: '',
      description: '',
      duration: '',
      poster: '',
      language: '',
      rating: '',
      trailer: '',
      cast: '',
      releaseDate: ''
    });
    setSelectedFile(null);
    setPreviewUrl(null);
  };

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setSelectedFile(file);
      
      // Create preview URL
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreviewUrl(reader.result);
      };
      reader.readAsDataURL(file);
      
      // Clear URL input if file is selected
      setFormData({ ...formData, poster: '' });
    }
  };

  const clearFile = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
  };

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString();
  };

  return (
    <div className="min-vh-100" style={{ background: '#f8f9fa' }}>
      {/* Admin Header */}
      <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
        <div className="container-fluid">
          <Link className="navbar-brand fw-bold" to="/admin/dashboard">
            🎬 CineBook Admin
          </Link>
          
          <div className="navbar-nav ms-auto">
            <div className="nav-item dropdown">
              <button 
                className="btn btn-outline-light dropdown-toggle"
                type="button"
                id="dropdownMenuButton"
                data-bs-toggle="dropdown"
                aria-expanded="false"
              >
                👤 {user?.name}
              </button>
              <ul className="dropdown-menu" aria-labelledby="dropdownMenuButton">
                <li><button className="dropdown-item" onClick={handleLogout}>Logout</button></li>
              </ul>
            </div>
          </div>
        </div>
      </nav>

      <div className="container-fluid">
        <div className="row">
          {/* Sidebar */}
          <div className="col-md-2 admin-sidebar">
            <div className="nav flex-column nav-pills">
              <Link className="nav-link" to="/admin/dashboard">
                📊 Dashboard
              </Link>
              <Link className="nav-link active" to="/admin/movies">
                🎬 Manage Movies
              </Link>
              <Link className="nav-link" to="/admin/shows">
                🎪 Manage Shows
              </Link>
              <Link className="nav-link" to="/admin/theaters">
                🏢 Manage Theaters
              </Link>
            </div>
          </div>

          {/* Main Content */}
          <div className="col-md-10 p-4">
            <div className="d-flex justify-content-between align-items-center mb-4">
              <h1 className="h3">Manage Movies</h1>
              <button
                className="btn btn-primary"
                onClick={() => {
                  resetForm();
                  setEditingMovie(null);
                  setShowModal(true);
                }}
              >
                ➕ Add New Movie
              </button>
            </div>

            {loading ? (
              <div className="text-center py-5">
                <div className="spinner-border text-primary" role="status">
                  <span className="visually-hidden">Loading...</span>
                </div>
              </div>
            ) : (
              <div className="card">
                <div className="card-body">
                  <div className="table-responsive">
                    <table className="table table-striped">
                      <thead>
                        <tr>
                          <th>Poster</th>
                          <th>Title</th>
                          <th>Genre</th>
                          <th>Language</th>
                          <th>Duration</th>
                          <th>Rating</th>
                          <th>Release Date</th>
                          <th>Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {movies.map(movie => (
                          <tr key={movie._id}>
                            <td>
                              <img
                                src={
                                  movie.poster 
                                    ? (movie.poster.startsWith('http') 
                                        ? movie.poster 
                                        : `http://localhost:5000${movie.poster}`
                                      )
                                    : 'https://via.placeholder.com/50x75?text=Poster'
                                }
                                alt={movie.title}
                                style={{ width: '50px', height: '75px', objectFit: 'cover' }}
                                className="rounded"
                                onError={(e) => {
                                  e.target.src = 'https://via.placeholder.com/50x75?text=Poster';
                                }}
                              />
                            </td>
                            <td>
                              <div>
                                <strong>{movie.title}</strong>
                                <br />
                                <small className="text-muted">
                                  {movie.description.substring(0, 50)}...
                                </small>
                              </div>
                            </td>
                            <td>{movie.genre}</td>
                            <td>{movie.language}</td>
                            <td>{movie.duration} mins</td>
                            <td>⭐ {movie.rating}</td>
                            <td>{formatDate(movie.releaseDate)}</td>
                            <td>
                              <div className="btn-group" role="group">
                                <button
                                  className="btn btn-sm btn-outline-primary"
                                  onClick={() => handleEdit(movie)}
                                >
                                  Edit
                                </button>
                                <button
                                  className="btn btn-sm btn-outline-danger"
                                  onClick={() => handleDelete(movie._id)}
                                >
                                  Delete
                                </button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>

                    {movies.length === 0 && (
                      <div className="text-center py-4">
                        <p className="text-muted">No movies found. Add your first movie!</p>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Movie Modal */}
      {showModal && (
        <div className="modal show d-block" style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <div className="modal-dialog modal-lg">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title">
                  {editingMovie ? 'Edit Movie' : 'Add New Movie'}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <form onSubmit={handleSubmit}>
                <div className="modal-body">
                  <div className="row">
                    <div className="col-md-6">
                      <div className="mb-3">
                        <label className="form-label">Title *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="title"
                          value={formData.title}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                    <div className="col-md-6">
                      <div className="mb-3">
                        <label className="form-label">Genre *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="genre"
                          value={formData.genre}
                          onChange={handleInputChange}
                          placeholder="Action, Comedy, Drama, etc."
                          required
                        />
                      </div>
                    </div>
                  </div>

                  <div className="mb-3">
                    <label className="form-label">Description *</label>
                    <textarea
                      className="form-control"
                      name="description"
                      value={formData.description}
                      onChange={handleInputChange}
                      rows="3"
                      required
                    ></textarea>
                  </div>

                  <div className="row">
                    <div className="col-md-4">
                      <div className="mb-3">
                        <label className="form-label">Duration (minutes) *</label>
                        <input
                          type="number"
                          className="form-control"
                          name="duration"
                          value={formData.duration}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                    <div className="col-md-4">
                      <div className="mb-3">
                        <label className="form-label">Language *</label>
                        <input
                          type="text"
                          className="form-control"
                          name="language"
                          value={formData.language}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                    <div className="col-md-4">
                      <div className="mb-3">
                        <label className="form-label">Rating (1-10) *</label>
                        <input
                          type="number"
                          step="0.1"
                          min="1"
                          max="10"
                          className="form-control"
                          name="rating"
                          value={formData.rating}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                  </div>

                  <div className="mb-3">
                    <label className="form-label">Movie Poster *</label>
                    
                    {/* File Upload Option */}
                    <div className="mb-2">
                      <label className="form-label text-muted small">📁 Choose File or Photo</label>
                      <input
                        type="file"
                        className="form-control"
                        accept="image/*"
                        onChange={handleFileChange}
                      />
                      {selectedFile && (
                        <div className="mt-2">
                          <small className="text-success">✓ Selected: {selectedFile.name}</small>
                          <button 
                            type="button" 
                            className="btn btn-sm btn-outline-danger ms-2"
                            onClick={clearFile}
                          >
                            Clear
                          </button>
                        </div>
                      )}
                    </div>
                    
                    {/* URL Option */}
                    <div className="mb-2">
                      <label className="form-label text-muted small">🔗 Or Poster URL</label>
                      <input
                        type="url"
                        className="form-control"
                        name="poster"
                        value={formData.poster}
                        onChange={handleInputChange}
                        placeholder="https://example.com/movie-poster.jpg"
                        disabled={selectedFile !== null}
                      />
                    </div>
                    
                    {/* Preview */}
                    {(previewUrl || (formData.poster && !selectedFile)) && (
                      <div className="mt-2">
                        <small className="text-muted">Preview:</small>
                        <div className="mt-1">
                          <img
                            src={previewUrl || (formData.poster?.startsWith('http') ? formData.poster : `http://localhost:5000${formData.poster}`)}
                            alt="Poster preview"
                            style={{ width: '100px', height: '150px', objectFit: 'cover' }}
                            className="rounded border"
                            onError={(e) => {
                              e.target.src = 'https://via.placeholder.com/100x150?text=Preview';
                            }}
                          />
                        </div>
                      </div>
                    )}
                    
                    <small className="text-muted">
                      * Choose a file from your computer or enter a URL. File upload is recommended.
                    </small>
                  </div>

                  <div className="mb-3">
                    <label className="form-label">Trailer URL</label>
                    <input
                      type="url"
                      className="form-control"
                      name="trailer"
                      value={formData.trailer}
                      onChange={handleInputChange}
                      placeholder="https://youtube.com/watch?v=..."
                    />
                  </div>

                  <div className="row">
                    <div className="col-md-6">
                      <div className="mb-3">
                        <label className="form-label">Cast (comma separated)</label>
                        <input
                          type="text"
                          className="form-control"
                          name="cast"
                          value={formData.cast}
                          onChange={handleInputChange}
                          placeholder="Actor 1, Actor 2, Actor 3"
                        />
                      </div>
                    </div>
                    <div className="col-md-6">
                      <div className="mb-3">
                        <label className="form-label">Release Date *</label>
                        <input
                          type="date"
                          className="form-control"
                          name="releaseDate"
                          value={formData.releaseDate}
                          onChange={handleInputChange}
                          required
                        />
                      </div>
                    </div>
                  </div>
                </div>
                <div className="modal-footer">
                  <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={() => setShowModal(false)}
                  >
                    Cancel
                  </button>
                  <button type="submit" className="btn btn-primary">
                    {editingMovie ? 'Update Movie' : 'Add Movie'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminMovies;
