import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import axios from 'axios';

const AdminDashboard = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalMovies: 0,
    totalUsers: 0,
    totalBookings: 0,
    totalRevenue: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardStats();
  }, []);

  const fetchDashboardStats = async () => {
    try {
      // Ensure we have a valid token
      const token = localStorage.getItem('token');
      if (token) {
        axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
      }
      
      const response = await axios.get('http://localhost:5000/api/movies/admin/dashboard-stats');
      if (response.data.success) {
        setStats(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching dashboard stats:', error);
      if (error.response?.status === 401 || error.response?.status === 403) {
        // Token expired or unauthorized, redirect to home page
        logout();
        navigate('/');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ height: '50vh' }}>
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="min-vh-100" style={{ background: '#f8f9fa' }}>
      {/* Admin Header */}
      <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
        <div className="container-fluid">
          <Link className="navbar-brand fw-bold" to="/admin/dashboard">
            🎬 FlixGo Admin
          </Link>
          
          <div className="navbar-nav ms-auto">
            <div className="nav-item dropdown">
              <button 
                className="btn btn-outline-light dropdown-toggle"
                type="button"
                id="dropdownMenuButton"
                data-bs-toggle="dropdown"
                aria-expanded="false"
              >
                👤 {user?.name}
              </button>
              <ul className="dropdown-menu" aria-labelledby="dropdownMenuButton">
                <li><button className="dropdown-item" onClick={handleLogout}>Logout</button></li>
              </ul>
            </div>
          </div>
        </div>
      </nav>

      <div className="container-fluid">
        <div className="row">
          {/* Sidebar */}
          <div className="col-md-2 admin-sidebar">
            <div className="nav flex-column nav-pills">
              <Link className="nav-link active" to="/admin/dashboard">
                📊 Dashboard
              </Link>
              <Link className="nav-link" to="/admin/movies">
                🎬 Manage Movies
              </Link>
              <Link className="nav-link" to="/admin/shows">
                🎪 Manage Shows
              </Link>
              <Link className="nav-link" to="/admin/theaters">
                🏢 Manage Theaters
              </Link>
            </div>
          </div>

          {/* Main Content */}
          <div className="col-md-10 p-4">
            <div className="d-flex justify-content-between align-items-center mb-4">
              <h1 className="h3">Admin Dashboard</h1>
              <div className="text-muted">
                Welcome back, {user?.name}
              </div>
            </div>

            {/* Stats Cards */}
            <div className="row mb-5">
              <div className="col-xl-3 col-md-6 mb-4">
                <div className="card border-left-primary shadow h-100 py-2 card-hover">
                  <div className="card-body">
                    <div className="row no-gutters align-items-center">
                      <div className="col mr-2">
                        <div className="text-xs font-weight-bold text-primary text-uppercase mb-1">
                          Total Movies
                        </div>
                        <div className="h5 mb-0 font-weight-bold text-gray-800">
                          {stats.totalMovies}
                        </div>
                      </div>
                      <div className="col-auto">
                        <div className="text-primary fs-1">🎬</div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div className="col-xl-3 col-md-6 mb-4">
                <div className="card border-left-success shadow h-100 py-2 card-hover">
                  <div className="card-body">
                    <div className="row no-gutters align-items-center">
                      <div className="col mr-2">
                        <div className="text-xs font-weight-bold text-success text-uppercase mb-1">
                          Total Users
                        </div>
                        <div className="h5 mb-0 font-weight-bold text-gray-800">
                          {stats.totalUsers}
                        </div>
                      </div>
                      <div className="col-auto">
                        <div className="text-success fs-1">👥</div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div className="col-xl-3 col-md-6 mb-4">
                <div className="card border-left-info shadow h-100 py-2 card-hover">
                  <div className="card-body">
                    <div className="row no-gutters align-items-center">
                      <div className="col mr-2">
                        <div className="text-xs font-weight-bold text-info text-uppercase mb-1">
                          Total Bookings
                        </div>
                        <div className="h5 mb-0 font-weight-bold text-gray-800">
                          {stats.totalBookings}
                        </div>
                      </div>
                      <div className="col-auto">
                        <div className="text-info fs-1">🎟️</div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div className="col-xl-3 col-md-6 mb-4">
                <div className="card border-left-warning shadow h-100 py-2 card-hover">
                  <div className="card-body">
                    <div className="row no-gutters align-items-center">
                      <div className="col mr-2">
                        <div className="text-xs font-weight-bold text-warning text-uppercase mb-1">
                          Total Revenue
                        </div>
                        <div className="h5 mb-0 font-weight-bold text-gray-800">
                          ₹{stats.totalRevenue?.toLocaleString() || 0}
                        </div>
                      </div>
                      <div className="col-auto">
                        <div className="text-warning fs-1">💰</div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Quick Actions */}
            <div className="row">
              <div className="col-lg-6 mb-4">
                <div className="card shadow">
                  <div className="card-header bg-primary text-white">
                    <h6 className="m-0 font-weight-bold">Quick Actions</h6>
                  </div>
                  <div className="card-body">
                    <div className="d-grid gap-2">
                      <Link to="/admin/movies" className="btn btn-outline-primary">
                        🎬 Add New Movie
                      </Link>
                      <Link to="/admin/shows" className="btn btn-outline-success">
                        🎪 Schedule New Show
                      </Link>
                    </div>
                  </div>
                </div>
              </div>

              <div className="col-lg-6 mb-4">
                <div className="card shadow">
                  <div className="card-header bg-info text-white">
                    <h6 className="m-0 font-weight-bold">System Status</h6>
                  </div>
                  <div className="card-body">
                    <div className="mb-3">
                      <div className="d-flex justify-content-between">
                        <span>Server Status</span>
                        <span className="badge bg-success">Online</span>
                      </div>
                    </div>
                    <div className="mb-3">
                      <div className="d-flex justify-content-between">
                        <span>Database</span>
                        <span className="badge bg-success">Connected</span>
                      </div>
                    </div>
                    <div className="mb-0">
                      <div className="d-flex justify-content-between">
                        <span>Last Updated</span>
                        <span className="text-muted">{new Date().toLocaleTimeString()}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
